// Extract all text content from the HTML - headings, paragraphs, features, etc.
const lines = FILE_CONTENT.split('\n');
const textContent = [];
let inStyle = false;
let inScript = false;

for (const line of lines) {
  const trimmed = line.trim();
  if (trimmed.includes('<style>') || trimmed.includes('<style ')) inStyle = true;
  if (trimmed.includes('</style>')) { inStyle = false; continue; }
  if (trimmed.includes('<script>') || trimmed.includes('<script ')) inScript = true;
  if (trimmed.includes('</script>')) { inScript = false; continue; }
  if (inStyle || inScript) continue;

  // Extract text from HTML tags
  const stripped = trimmed.replace(/<[^>]+>/g, ' ').replace(/&[a-z]+;/g, ' ').replace(/\s+/g, ' ').trim();
  if (stripped && stripped.length > 1) {
    textContent.push(stripped);
  }
}

console.log(textContent.join('\n'));
